+                user_base: 0x1000,
+                user_size: 256,
+                generation: 1,
+                state: 0,
+            },
+            ArenaSlotSnapshot {
+                user_base: 0x2000,
+                user_size: 512,
+                generation: 1,
+                state: 0,
+            },
+        ],
+    });
+
+    let mut reader = RcuReader::new(&index);
+
+    // Read-side lookup: no locks.
+    let idx = reader.read();
+    let slot = idx
+        .slots
+        .iter()
+        .find(|s| s.user_base == 0x1000)
